import os
from cryptography.hazmat.primitives.ciphers.aead import AESGCM
from cryptography.exceptions import InvalidTag


def generate_key() -> bytes:
    """
    Generate a random 256‑bit (32‑byte) key suitable for AES‑GCM.
    """
    return os.urandom(32)          # 32 bytes = 256 bits


def generate_nonce() -> bytes:
    """
    Generate a fresh 96‑bit (12‑byte) nonce for AES‑GCM.
    The 96‑bit size is recommended by NIST for GCM.
    """
    return os.urandom(12)          # 12 bytes = 96 bits


def encrypt(key: bytes, plaintext: str) -> tuple[bytes, bytes, bytes]:
    """
    Encrypt `plaintext` using AES‑GCM with the provided `key`.

    Returns a tuple:
        (ciphertext, nonce, tag)

    - `ciphertext` : the encrypted data (bytes)
    - `nonce`      : the nonce used for this encryption (bytes)
    - `tag`        : the authentication tag (bytes)
    """
    # Create an AESGCM cipher object with the supplied key
    aesgcm = AESGCM(key)

    # Generate a unique nonce for this encryption operation
    nonce = generate_nonce()

    # Encode the plaintext string to bytes (UTF‑8)
    pt_bytes = plaintext.encode("utf-8")

    # Perform encryption; AESGCM.encrypt returns ciphertext || tag concatenated.
    # We ask for the tag separately by using `encrypt` and then slicing,
    # but the library returns the tag appended, so we split it.
    # The tag length for AES‑GCM is 16 bytes.
    ct_with_tag = aesgcm.encrypt(nonce, pt_bytes, associated_data=None)

    # Separate ciphertext and tag
    tag = ct_with_tag[-16:]          # last 16 bytes = authentication tag
    ciphertext = ct_with_tag[:-16]   # everything before the tag

    return ciphertext, nonce, tag


def decrypt(key: bytes, nonce: bytes, ciphertext: bytes, tag: bytes) -> str:
    """
    Decrypt `ciphertext` using AES‑GCM with the provided `key`, `nonce`, and `tag`.

    Returns the original plaintext string.

    Raises:
        InvalidTag: if the authentication tag does not verify (tampered data).
    """
    aesgcm = AESGCM(key)

    # Re‑assemble ciphertext and tag as expected by the library
    ct_with_tag = ciphertext + tag

    try:
        # Decrypt and verify the tag in one step
        pt_bytes = aesgcm.decrypt(nonce, ct_with_tag, associated_data=None)
    except InvalidTag as exc:
        # Re‑raise with a clearer message (optional)
        raise InvalidTag("Authentication tag verification failed – data may be corrupted or tampered.") from exc

    # Decode bytes back to string (UTF‑8)
    return pt_bytes.decode("utf-8")


# -------------------------------------------------------------------------
# Demonstration
