if __name__ == "__main__":
    # 1. Generate a random 256‑bit key (in practice, store this securely)
    key = generate_key()
    print(f"Key (hex): {key.hex()}")

    # 2. Example plaintext message
    message = "Hello, AES‑GCM! This is a confidential message."
    print(f"Original plaintext: {message}")

    # 3. Encrypt the message
    ciphertext, nonce, tag = encrypt(key, message)
    print(f"Ciphertext (hex): {ciphertext.hex()}")
    print(f"Nonce (hex):      {nonce.hex()}")
    print(f"Tag (hex):        {tag.hex()}")

    # 4. Decrypt the message (successful case)
    try:
        decrypted = decrypt(key, nonce, ciphertext, tag)
        print(f"Decrypted plaintext: {decrypted}")
        assert decrypted == message, "Decrypted text does not match original!"
        print("✅ Decryption successful and matches original plaintext.")
    except InvalidTag as e:
        print(f"❌ Decryption failed: {e}")

    # 5. Demonstrate authentication failure by corrupting the ciphertext
    corrupted_ct = bytearray(ciphertext)
    corrupted_ct[0] ^= 0xFF  # flip bits in the first byte
    print("\n--- Tampered ciphertext test ---")
    try:
        decrypt(key, nonce, bytes(corrupted_ct), tag)
    except InvalidTag as e:
        print(f"❌ Expected failure caught: {e}")
